"use client"
import { useEffect, useMemo, useRef, useState } from 'react'
import { motion } from 'framer-motion'

const DEFAULT_SECONDS = 10

export default function DiscussionStart({ onContinue }: { onContinue: () => void }) {
  const [musicOn, setMusicOn] = useState(false)
  const [countdown, setCountdown] = useState(DEFAULT_SECONDS)
  const intervalRef = useRef<number | null>(null)
  const audioRef = useRef<AudioContext | null>(null)
  const gainRef = useRef<GainNode | null>(null)
  const oscRef = useRef<OscillatorNode | null>(null)

  const progress = useMemo(() => (countdown / DEFAULT_SECONDS) * 100, [countdown])

  useEffect(() => {
    if (musicOn) {
      try {
        const ctx = new (window.AudioContext || (window as any).webkitAudioContext)()
        const osc = ctx.createOscillator()
        const gain = ctx.createGain()
        osc.type = 'triangle'
        osc.frequency.value = 110
        gain.gain.value = 0.02
        osc.connect(gain)
        gain.connect(ctx.destination)
        osc.start()
        audioRef.current = ctx
        gainRef.current = gain
        oscRef.current = osc
      } catch (error) {
        console.warn('Audio unavailable', error)
      }
    }

    return () => {
      if (oscRef.current) oscRef.current.stop()
      if (audioRef.current) audioRef.current.close()
      oscRef.current = null
      gainRef.current = null
      audioRef.current = null
    }
  }, [musicOn])

  useEffect(() => {
    if (!musicOn) return
    if (intervalRef.current) window.clearInterval(intervalRef.current)
    intervalRef.current = window.setInterval(() => {
      setCountdown((current) => {
        if (current <= 1) {
          if (intervalRef.current) window.clearInterval(intervalRef.current)
          return 0
        }
        return current - 1
      })
    }, 1000)
    return () => {
      if (intervalRef.current) window.clearInterval(intervalRef.current)
    }
  }, [musicOn])

  return (
    <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} className="relative overflow-hidden rounded-3xl bg-gradient-to-br from-purple-950 via-black to-indigo-950 p-6 shadow-2xl">
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_top,_rgba(138,43,226,0.35),_transparent_40%)] opacity-60 pointer-events-none" />
      <div className="absolute inset-x-10 top-8 h-24 rounded-full bg-white/5 blur-2xl animate-pulse" />
      <div className="relative space-y-6">
        <div className="text-center">
            <div className="text-sm text-muted uppercase tracking-[0.35em]">Prepare for discussion</div>
            <div className="mt-4 text-4xl font-black neon">DISCUSSION STARTS NOW</div>
          </div>

        <div className="rounded-3xl border border-white/10 bg-black/20 p-4">
          <div className="flex items-center justify-between text-sm text-gray-300 mb-3">
            <span>Countdown</span>
            <span>{countdown}s</span>
          </div>
          <div className="h-3 rounded-full bg-white/10 overflow-hidden">
            <div className="h-full bg-primary transition-all duration-500" style={{ width: `${progress}%` }} />
          </div>
        </div>

        <div className="rounded-3xl border border-white/10 bg-black/10 p-4 space-y-3">
          <div className="flex items-center justify-between">
            <div>
              <div className="text-sm text-gray-300">Suspense Music</div>
              <div className="text-xs text-gray-500">Use if you want tension.</div>
            </div>
            <button onClick={() => setMusicOn((on) => !on)} className={`px-4 py-2 rounded-full ${musicOn ? 'bg-primary text-white' : 'bg-white/5 text-white'}`}>
              {musicOn ? 'On' : 'Off'}
            </button>
          </div>
        </div>

        <div className="space-y-3">
          <p className="text-center text-sm text-gray-300">This is the moment the app steps back. Now your group takes over with the drama.</p>
          <button onClick={() => { if (intervalRef.current) window.clearInterval(intervalRef.current); onContinue() }} className="w-full rounded-2xl bg-primary py-4 text-lg font-semibold text-white shadow-xl">
            Start Discussion
          </button>
        </div>
      </div>
    </motion.div>
  )
}
